command:
// ======================================
// 异常结算样板宏：施加状态效果
// ======================================
// 当异常值满槽时自动执行，对目标施加指定的状态效果。
// 使用方法：复制此宏到宏目录，修改下方配置，然后在遗名之穹配置中关联。
// 传入参数：{ actor, token, speaker, damageType }
// ======================================

// ===== 用户配置区域 =====
const CONDITION_SLUG = "stunned";   // 状态效果标识符
//   常用状态：stunned（震慑）、frightened（恐惧）、sickened（恶心）、
//   clumsy（笨拙）、enfeebled（力竭）、drained（吸取）、
//   slowed（减速）、stupefied（愚钝）、blinded（目盲）、
//   deafened（耳聋）、fatigued（疲乏）、paralyzed（麻痹）、
//   prone（倒地）、off-guard（措手不及）
const CONDITION_VALUE = 1;          // 状态等级（如 stunned 1、frightened 2）；部分状态无等级则忽略此值
// ===== 配置结束 =====

if (!actor) {
  ui.notifications.warn("异常结算宏：未找到目标角色");
  return;
}

try {
  // 获取伤害类型的本地化名称
  const typeLabel = CONFIG?.PF2E?.damageTypes?.[damageType]
    ? game.i18n.localize(CONFIG.PF2E.damageTypes[damageType])
    : damageType;

  // 尝试使用 PF2e 系统的 increaseCondition 方法
  if (typeof actor.increaseCondition === "function") {
    const existing = actor.getCondition?.(CONDITION_SLUG);
    if (existing) {
      // 如果已有此状态，增加其等级
      const currentValue = existing.value ?? 0;
      const targetValue = Math.max(currentValue, CONDITION_VALUE);
      if (targetValue > currentValue) {
        for (let i = currentValue; i < targetValue; i++) {
          await actor.increaseCondition(CONDITION_SLUG);
        }
      }
    } else {
      // 首次施加状态
      await actor.increaseCondition(CONDITION_SLUG, { value: CONDITION_VALUE });
    }
  } else {
    // Fallback：通过合集获取状态效果物品
    const conditionItem = game.pf2e?.ConditionManager?.getCondition(CONDITION_SLUG);
    if (conditionItem) {
      const itemData = conditionItem.toObject();
      if (itemData.system?.value?.isValued) {
        itemData.system.value.value = CONDITION_VALUE;
      }
      await actor.createEmbeddedDocuments("Item", [itemData]);
    } else {
      ui.notifications.warn(`异常结算宏：无法找到状态效果 "${CONDITION_SLUG}"`);
      return;
    }
  }

  // 获取状态的本地化名称
  const conditionLabel = game.pf2e?.ConditionManager?.getCondition(CONDITION_SLUG)?.name ?? CONDITION_SLUG;

  // 发送聊天消息
  const valueText = CONDITION_VALUE > 0 ? ` ${CONDITION_VALUE}` : "";
  const content = `
    <div style="padding: 8px; border-left: 4px solid #6f42c1; background: #f8f0ff; border-radius: 4px;">
      <p style="margin: 0 0 6px; font-weight: bold; color: #6f42c1;">
        <i class="fas fa-dizzy"></i> 异常结算：状态效果
      </p>
      <p style="margin: 0;">
        <strong>${actor.name}</strong> 的 <strong>${typeLabel}</strong> 异常值已满！
      </p>
      <p style="margin: 4px 0 0;">
        获得状态效果：<strong>${conditionLabel}${valueText}</strong>
      </p>
    </div>
  `;
  await ChatMessage.create({ speaker, content });

} catch (err) {
  console.error("异常结算宏执行失败:", err);
  ui.notifications.error("异常结算宏执行失败，请查看控制台");
}
